__kernel void hotspotOpt1(__global const float *p,
                          __global const float *tIn,
                          __global float *tOut,
                          float sdc,
                          int nx, int ny, int nz,
                          float ce, float cw,
                          float cn, float cs,
                          float ct, float cb,
                          float cc)
{
    const float amb_temp = 80.0f;

    const int i = (int)get_global_id(0);
    const int j = (int)get_global_id(1);

    if (i >= nx || j >= ny || nz <= 0)
        return;

    int c = i + j * nx;
    const int xy = nx * ny;

    int W = (i == 0)    ? c : c - 1;
    int E = (i == nx-1) ? c : c + 1;
    int N = (j == 0)    ? c : c - nx;
    int S = (j == ny-1) ? c : c + nx;

    float temp1, temp2, temp3;

    if (nz == 1) {
        temp1 = temp2 = temp3 = tIn[c];
        tOut[c] = cc * temp2 + cw * tIn[W] + ce * tIn[E] + cs * tIn[S]
                + cn * tIn[N] + cb * temp1 + ct * temp3 + sdc * p[c] + ct * amb_temp;
        return;
    }

    temp1 = temp2 = tIn[c];
    temp3 = tIn[c + xy];
    tOut[c] = cc * temp2 + cw * tIn[W] + ce * tIn[E] + cs * tIn[S]
            + cn * tIn[N] + cb * temp1 + ct * temp3 + sdc * p[c] + ct * amb_temp;

    c += xy;
    W += xy;
    E += xy;
    N += xy;
    S += xy;

    for (int k = 1; k < nz - 1; ++k) {
        temp1 = temp2;
        temp2 = temp3;
        temp3 = tIn[c + xy];
        tOut[c] = cc * temp2 + cw * tIn[W] + ce * tIn[E] + cs * tIn[S]
                + cn * tIn[N] + cb * temp1 + ct * temp3 + sdc * p[c] + ct * amb_temp;

        c += xy;
        W += xy;
        E += xy;
        N += xy;
        S += xy;
    }

    temp1 = temp2;
    temp2 = temp3;
    tOut[c] = cc * temp2 + cw * tIn[W] + ce * tIn[E] + cs * tIn[S]
            + cn * tIn[N] + cb * temp1 + ct * temp3 + sdc * p[c] + ct * amb_temp;
}
